// Hybrid simulator (QEMU + Verilator vsim) state-exchange ABI - v1.
//
// This header is the wire contract between the QEMU TCG plugin
// (hybrid/qemu_plugin/) and vsim (src/hybrid/). Both sides write/read
// `struct hybrid_state_v1` byte-for-byte through a shared file.
//
// Stability rule: never repurpose offsets within a published version. Add new
// fields by bumping HYBRID_STATE_VERSION and consuming bytes from `reserved`,
// or by introducing v2 alongside v1.
//
// C and C++ both compile this header. No SystemC, no spdlog, no LIEF.

#ifndef HYBRID_STATE_ABI_H
#define HYBRID_STATE_ABI_H

#include <stdint.h>
#include <stddef.h>

#ifdef __cplusplus
extern "C" {
#endif

// 'AHYB' as the file's first four bytes when read on a little-endian host.
// 'A'=0x41 'H'=0x48 'Y'=0x59 'B'=0x42 -> 0x42594841.
#define HYBRID_STATE_MAGIC   0x42594841u
#define HYBRID_STATE_VERSION 1u

// flags (bitmask)
#define HYBRID_FLAG_RV64 (1u << 0)
#define HYBRID_FLAG_FP   (1u << 1)
#define HYBRID_FLAG_V    (1u << 2)

// V-extension regfile width upper bound. 1024 bits = 128 bytes covers all
// AX45MPV configurations and leaves headroom for future cores.
#define HYBRID_VLEN_BYTES_MAX 128

// Per RISC-V spec: 64 PMP entries, packed into pmpcfg CSRs (8 entries per
// 64-bit pmpcfg on RV64 -> 8 CSRs; we reserve 16 to stay forward-compatible
// with 16-byte packings or RV32 layouts).
#define HYBRID_PMP_CFG_NUM  16
#define HYBRID_PMP_ADDR_NUM 64

// All fields are naturally 8-byte aligned so the layout is trivially packed.
// No __attribute__((packed)) is needed and avoiding it preserves aligned
// loads/stores. The build asserts (state_abi_check.h) lock the layout.
struct hybrid_state_v1 {
  // Header (32 bytes)
  uint32_t magic;     // = HYBRID_STATE_MAGIC
  uint32_t version;   // = HYBRID_STATE_VERSION
  uint32_t flags;     // HYBRID_FLAG_*
  uint32_t hart_id;   // 0-based hart index
  uint64_t pc;        // resume PC
  uint64_t priv;      // privilege mode at handoff (0=U, 1=S, 3=M)

  // Architectural register files
  uint64_t gpr[32];   // x0..x31 (x0 always reads as 0; carried for symmetry)
  uint64_t fpr[32];   // f0..f31 (only valid when HYBRID_FLAG_FP set)

  // M-mode CSRs (selected, read/written via DM Abstract Commands on vsim side)
  uint64_t mstatus;
  uint64_t mepc;
  uint64_t mtvec;
  uint64_t mcause;
  uint64_t mtval;
  uint64_t mscratch;
  uint64_t medeleg;
  uint64_t mideleg;
  uint64_t mip;
  uint64_t mie;
  uint64_t mcycle;
  uint64_t minstret;
  uint64_t satp;

  // PMP
  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];

  // V-extension scalar state and regfile
  uint64_t vstart;
  uint64_t vtype;
  uint64_t vl;
  uint64_t vlenb;
  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];

  // Forward-compatibility scratch. Zero-initialise on write.
  uint8_t  reserved[256];
};

#ifdef __cplusplus
}  // extern "C"
#endif

// Compile-time layout lock. Including unconditionally so every consumer
// (vsim, plugin, tests) catches drift at the point of inclusion.
#include "hybrid/state_abi_check.h"

#endif  // HYBRID_STATE_ABI_H
===FILE: hybrid/include/hybrid/state_abi_check.h===
// Compile-time layout lock for hybrid_state_v1.
//
// Any drift in the offset of a published field, or a size change to an array,
// breaks every translation unit that includes state_abi.h. This is the
// intended behaviour: the ABI is a wire contract.
//
// Adding a NEW field consumes bytes from `reserved`; the existing asserts must
// continue to hold and a new assert is added for the new field.

#ifndef HYBRID_STATE_ABI_CHECK_H
#define HYBRID_STATE_ABI_CHECK_H

#include "hybrid/state_abi.h"

#if defined(__cplusplus)
#  define HYBRID_STATIC_ASSERT(expr, msg) static_assert((expr), msg)
#else
#  define HYBRID_STATIC_ASSERT(expr, msg) _Static_assert((expr), msg)
#endif

// Header
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, magic)   == 0,  "magic@0");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, version) == 4,  "version@4");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, flags)   == 8,  "flags@8");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, hart_id) == 12, "hart_id@12");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pc)      == 16, "pc@16");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, priv)    == 24, "priv@24");

// Register files
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, gpr) == 32,  "gpr@32");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, fpr) == 288, "fpr@288");

// CSRs (M-mode)
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mstatus)  == 544, "mstatus@544");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mepc)     == 552, "mepc@552");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtvec)    == 560, "mtvec@560");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcause)   == 568, "mcause@568");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtval)    == 576, "mtval@576");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mscratch) == 584, "mscratch@584");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, medeleg)  == 592, "medeleg@592");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mideleg)  == 600, "mideleg@600");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mip)      == 608, "mip@608");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mie)      == 616, "mie@616");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcycle)   == 624, "mcycle@624");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, minstret) == 632, "minstret@632");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, satp)     == 640, "satp@640");

// PMP
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpcfg)  == 648, "pmpcfg@648");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpaddr) == 776, "pmpaddr@776");

// V-extension
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vstart) == 1288, "vstart@1288");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vtype)  == 1296, "vtype@1296");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vl)     == 1304, "vl@1304");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vlenb)  == 1312, "vlenb@1312");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vreg)   == 1320, "vreg@1320");

// Reserved + total size
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, reserved) == 5416, "reserved@5416");
HYBRID_STATIC_ASSERT(sizeof(struct hybrid_state_v1) == 5672, "hybrid_state_v1 total size");

// Sub-array sizes
HYBRID_STATIC_ASSERT(HYBRID_VLEN_BYTES_MAX == 128, "VLEN bytes pinned to 1024-bit");
HYBRID_STATIC_ASSERT(HYBRID_PMP_CFG_NUM == 16,     "pmpcfg slot count");
HYBRID_STATIC_ASSERT(HYBRID_PMP_ADDR_NUM == 64,    "pmpaddr entry count");

#endif  // HYBRID_STATE_ABI_CHECK_H
