// ABI contract for hybrid handoff state: magic/version, layout, roundtrip.

#include "hybrid/state_abi.h"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdint>
#include <cstring>
#include <type_traits>

TEST_CASE("magic and version are stable wire constants")
{
  CHECK(HYBRID_STATE_MAGIC == 0x42594841u);
  CHECK(HYBRID_STATE_VERSION == 1u);
}

TEST_CASE("struct is standard-layout, trivially copyable, no tail padding")
{
  CHECK(std::is_standard_layout_v<hybrid_state_v1>);
  CHECK(std::is_trivially_copyable_v<hybrid_state_v1>);
  CHECK(sizeof(hybrid_state_v1) % 8 == 0);
}

TEST_CASE("header field offsets")
{
  CHECK(offsetof(hybrid_state_v1, magic) == 0);
  CHECK(offsetof(hybrid_state_v1, version) == 4);
  CHECK(offsetof(hybrid_state_v1, flags) == 8);
  CHECK(offsetof(hybrid_state_v1, hart_id) == 12);
  CHECK(offsetof(hybrid_state_v1, pc) == 16);
  CHECK(offsetof(hybrid_state_v1, priv) == 24);
}

TEST_CASE("GPR and FPR are 32 * uint64_t each, contiguous")
{
  hybrid_state_v1 s{};
  CHECK(offsetof(hybrid_state_v1, gpr) == 32);
  CHECK(sizeof(s.gpr) == 32 * sizeof(uint64_t));
  CHECK(offsetof(hybrid_state_v1, fpr) == 32 + 32 * 8);
  CHECK(sizeof(s.fpr) == 32 * sizeof(uint64_t));
}

TEST_CASE("V-extension fields use compile-time MAX_VLEN constant")
{
  hybrid_state_v1 s{};
  CHECK(HYBRID_VLEN_BYTES_MAX >= 16);  // RVV minimum VLEN=128 -> 16 bytes
  CHECK((HYBRID_VLEN_BYTES_MAX & (HYBRID_VLEN_BYTES_MAX - 1)) == 0);  // power of 2
  CHECK(sizeof(s.vreg) == 32u * HYBRID_VLEN_BYTES_MAX);
}

