// Compile-time layout lock for hybrid_state_v1. The ABI is a wire contract,
// so any offset or size drift must break every consumer at compile time.

#ifndef HYBRID_STATE_ABI_CHECK_H
#define HYBRID_STATE_ABI_CHECK_H

#include "hybrid/state_abi.h"

// C++20 has static_assert; C11+ has _Static_assert. Pick the one that exists.
#ifndef __cplusplus
#  define static_assert _Static_assert
#endif

static_assert(offsetof(struct hybrid_state_v1, magic)    == 0,    "magic@0");
static_assert(offsetof(struct hybrid_state_v1, version)  == 4,    "version@4");
static_assert(offsetof(struct hybrid_state_v1, flags)    == 8,    "flags@8");
static_assert(offsetof(struct hybrid_state_v1, hart_id)  == 12,   "hart_id@12");
static_assert(offsetof(struct hybrid_state_v1, pc)       == 16,   "pc@16");
static_assert(offsetof(struct hybrid_state_v1, priv)     == 24,   "priv@24");

static_assert(offsetof(struct hybrid_state_v1, gpr)      == 32,   "gpr@32");
static_assert(offsetof(struct hybrid_state_v1, fpr)      == 288,  "fpr@288");

static_assert(offsetof(struct hybrid_state_v1, mstatus)  == 544,  "mstatus@544");
static_assert(offsetof(struct hybrid_state_v1, mepc)     == 552,  "mepc@552");
static_assert(offsetof(struct hybrid_state_v1, mtvec)    == 560,  "mtvec@560");
static_assert(offsetof(struct hybrid_state_v1, mcause)   == 568,  "mcause@568");
static_assert(offsetof(struct hybrid_state_v1, mtval)    == 576,  "mtval@576");
static_assert(offsetof(struct hybrid_state_v1, mscratch) == 584,  "mscratch@584");
static_assert(offsetof(struct hybrid_state_v1, medeleg)  == 592,  "medeleg@592");
static_assert(offsetof(struct hybrid_state_v1, mideleg)  == 600,  "mideleg@600");
static_assert(offsetof(struct hybrid_state_v1, mip)      == 608,  "mip@608");
static_assert(offsetof(struct hybrid_state_v1, mie)      == 616,  "mie@616");
static_assert(offsetof(struct hybrid_state_v1, mcycle)   == 624,  "mcycle@624");
static_assert(offsetof(struct hybrid_state_v1, minstret) == 632,  "minstret@632");
static_assert(offsetof(struct hybrid_state_v1, satp)     == 640,  "satp@640");

static_assert(offsetof(struct hybrid_state_v1, pmpcfg)   == 648,  "pmpcfg@648");
static_assert(offsetof(struct hybrid_state_v1, pmpaddr)  == 776,  "pmpaddr@776");

static_assert(offsetof(struct hybrid_state_v1, vstart)   == 1288, "vstart@1288");
static_assert(offsetof(struct hybrid_state_v1, vtype)    == 1296, "vtype@1296");
static_assert(offsetof(struct hybrid_state_v1, vl)       == 1304, "vl@1304");
static_assert(offsetof(struct hybrid_state_v1, vlenb)    == 1312, "vlenb@1312");
static_assert(offsetof(struct hybrid_state_v1, vreg)     == 1320, "vreg@1320");

static_assert(offsetof(struct hybrid_state_v1, reserved) == 5416, "reserved@5416");
static_assert(sizeof(struct hybrid_state_v1) == 5672, "hybrid_state_v1 total size");

static_assert(HYBRID_VLEN_BYTES_MAX == 128, "VLEN bytes pinned to 1024-bit");
static_assert(HYBRID_PMP_CFG_NUM    == 16,  "pmpcfg slot count");
static_assert(HYBRID_PMP_ADDR_NUM   == 64,  "pmpaddr entry count");

#endif  // HYBRID_STATE_ABI_CHECK_H

// Wire contract between the QEMU TCG plugin and vsim. Both sides write/read
// `struct hybrid_state_v1` byte-for-byte through a shared file.
//
// Stability: never repurpose offsets within a published version. Add new
// fields by consuming bytes from `reserved`, or by introducing v2 alongside.
//
// C and C++ both compile this header.

#ifndef HYBRID_STATE_ABI_H
#define HYBRID_STATE_ABI_H

#include <stdint.h>
#include <stddef.h>

#ifdef __cplusplus
extern "C" {
#endif

#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
#define HYBRID_STATE_VERSION 1u

#define HYBRID_FLAG_RV64 (1u << 0)
#define HYBRID_FLAG_FP   (1u << 1)
#define HYBRID_FLAG_V    (1u << 2)

// 1024-bit VLEN upper bound: covers all AX45MPV configurations.
#define HYBRID_VLEN_BYTES_MAX 128

// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
#define HYBRID_PMP_CFG_NUM  16
#define HYBRID_PMP_ADDR_NUM 64

// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
// unnecessary and would force unaligned access codegen. Layout is locked by
// the static_asserts in state_abi_check.h.
struct hybrid_state_v1 {
  uint32_t magic;
  uint32_t version;
  uint32_t flags;
  uint32_t hart_id;
  uint64_t pc;
  uint64_t priv;  // 0=U, 1=S, 3=M

  uint64_t gpr[32];
  uint64_t fpr[32];

  uint64_t mstatus;
  uint64_t mepc;
  uint64_t mtvec;
  uint64_t mcause;
  uint64_t mtval;
  uint64_t mscratch;
  uint64_t medeleg;
  uint64_t mideleg;
  uint64_t mip;
  uint64_t mie;
  uint64_t mcycle;
  uint64_t minstret;
  uint64_t satp;

  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];

  uint64_t vstart;
  uint64_t vtype;
  uint64_t vl;
  uint64_t vlenb;
  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];

  uint8_t  reserved[256];  // zero-initialise on write
};

#ifdef __cplusplus
}  // extern "C"
#endif

#include "hybrid/state_abi_check.h"

#endif  // HYBRID_STATE_ABI_H

