#pragma once

#include "memory_region.hpp"

#include <spdlog/spdlog.h>
#include <systemc>
#include <tlm>
#include <tlm_utils/simple_target_socket.h>

#include <cstdint>

template<std::size_t BusWidth>
class SimpleMemory : public sc_core::sc_module
{
public:
  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;

  const MemoryRegion region;
  const MemoryRegion alias_region;
  std::vector<uint8_t> data;
  unsigned latency = 1;
  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
    "tsck"};

  SimpleMemory(const sc_core::sc_module_name& name,
               const MemoryRegion& region,
               const MemoryRegion& alias_region = {INVALID_ADDRESS,
                                                   INVALID_ADDRESS})
      : sc_core::sc_module{name},
        region(region),
        alias_region(alias_region),
        data(region.end_address - region.base_address)
  {
    this->socket.register_b_transport(this, &SimpleMemory::b_transport);
  }

  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
  {
    auto cycles = handle_trans(trans);
    if (trans.get_response_status() == tlm::TLM_INCOMPLETE_RESPONSE)
      trans.set_response_status(tlm::TLM_OK_RESPONSE);
    delay += sc_core::sc_time(cycles, sc_core::SC_NS);
  }

private:
  auto handle_trans(tlm::tlm_generic_payload& trans) -> unsigned
  {
    const auto addr = trans.get_address();
    const auto len = trans.get_data_length();
    const auto ptr = trans.get_data_ptr();
    const auto byte_enable_len = trans.get_byte_enable_length();
    const auto byte_enable_ptr = trans.get_byte_enable_ptr();

    spdlog::debug("mem: {}, addr={:#x}, len={}",
                  trans.is_read() ? "read" : "write", addr, len);

    uint64_t offset;
    if (region.contains({addr, addr + len})) [[likely]] {
      offset = addr - this->region.base_address;
    } else if (alias_region.contains({addr, addr + len})) {
      offset = addr - this->alias_region.base_address;
    } else {
      spdlog::error(
        "transaction is out of bounds of memory region [{:#x}-{:#x}]",
        this->region.base_address, this->region.end_address);
      trans.set_response_status(tlm::TLM_ADDRESS_ERROR_RESPONSE);
      return latency;
    }
    const auto buf = std::span{ptr, ptr + len};
    if (trans.is_read()) [[likely]] {
      std::copy_n(this->data.begin() + offset, len, buf.begin());
      return latency;
    }

    if (!trans.is_write()) [[unlikely]] {
      throw std::runtime_error("unimplemented");
    }

    // write operation
    if (byte_enable_len == 0) [[likely]] {
      std::copy_n(buf.begin(), len, this->data.begin() + offset);
      return latency;
    }

    // handle byte strobe if needed
    // AXI/AHB may split an un-aligned write into multiple aligned writes
    // with byte enable mask
    assert(byte_enable_len == len);
    for (unsigned i = 0; i < len; i++) {
      if (byte_enable_ptr[i] == 0xff)
        this->data[offset + i] = buf[i];
    }
    return latency;
  }
};

