concept XLenT =
  std::is_same_v<T, std::uint32_t> || std::is_same_v<T, std::uint64_t>;

template<XLenT xlen_t>
void read_elf_into_memory(const LIEF::ELF::Binary& elf,
                          const xlen_t base_addr,
                          const std::span<uint8_t> buf)
{
  namespace ELF = LIEF::ELF;

  assert(buf.size() < std::numeric_limits<xlen_t>::max() - base_addr);

  if (std::is_same_v<xlen_t, uint32_t>
      && elf.type() != ELF::ELF_CLASS::ELFCLASS32) [[unlikely]]
    throw std::runtime_error("Executable is not of ELFCLASS32");
  else if (std::is_same_v<xlen_t, uint64_t>
           && elf.type() != ELF::ELF_CLASS::ELFCLASS64) [[unlikely]]
    throw std::runtime_error("Executable is not of ELFCLASS64");

  if (elf.header().identity_data() != ELF::ELF_DATA::ELFDATA2LSB) [[unlikely]]
    throw std::runtime_error("Only little-endian executables are supported");

  if (elf.header().machine_type() != ELF::ARCH::EM_RISCV) [[unlikely]]
    throw std::runtime_error("Not EM_RISCV");

