TEST_CASE("simple_memory read write alias and bounds")
{
  SimpleMemory<32> mem{"mem", MemoryRegion{0x1000, 0x10ff},
                       MemoryRegion{0x2000, 0x20ff}};
  mem.latency = 3;

  {
    std::array<uint8_t, 4> write_data{0xde, 0xad, 0xbe, 0xef};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x1000);
    gp.set_data_ptr(write_data.data());
    gp.set_data_length(write_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(delay == sc_core::sc_time(3, sc_core::SC_NS));
    CHECK(mem.data[0] == 0xde);
    CHECK(mem.data[1] == 0xad);
    CHECK(mem.data[2] == 0xbe);
    CHECK(mem.data[3] == 0xef);
  }

  {
    std::array<uint8_t, 4> read_data{};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_READ_COMMAND);
    gp.set_address(0x1000);
    gp.set_data_ptr(read_data.data());
    gp.set_data_length(read_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
