    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(read_data == std::array<uint8_t, 4>{0xde, 0xad, 0xbe, 0xef});
  }

  {
    std::array<uint8_t, 4> alias_data{0x11, 0x22, 0x33, 0x44};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x2000);
    gp.set_data_ptr(alias_data.data());
    gp.set_data_length(alias_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(mem.data[0] == 0x11);
    CHECK(mem.data[1] == 0x22);
    CHECK(mem.data[2] == 0x33);
