#pragma once

#include <cstdint>

#include <format>
#include <limits>
#include <stdexcept>

/**
 * A memory region in the range of `[base_address, end_address)`.
 * The constructor takes an inclusive end address and stores it as exclusive.
 * e.g. memory_region(0x80000000, 0x8fffffff) stores base=0x80000000,
 *      end=0x90000000.
 */
struct MemoryRegion
{
  using addr_type = uint64_t;

  const addr_type base_address; // inclusive
  const addr_type end_address; // exclusive (stored as param + 1)

  /**
   * @param base_address The base address of the memory region (inclusive).
   * @param end_address The end address of the memory region (inclusive).
   * @throws std::invalid_argument if base_address > end_address.
   * @example memory_region(0x00, 0xff) represents [0x00, 0x100)
   */
  MemoryRegion(const addr_type base_address, const addr_type end_address)
      : base_address{base_address}, end_address{end_address + 1}
  {
    if (base_address > end_address)
      throw std::invalid_argument(std::format(
        "invalid memory region: [{:#x}-{:#x}]", base_address, end_address));
  }

  auto contains(const addr_type addr) const noexcept -> bool
  {
    return addr >= this->base_address && addr < this->end_address;
  }

  auto contains(const MemoryRegion& other) const noexcept -> bool
  {
    return other.base_address >= this->base_address
        && other.end_address <= this->end_address;
  }

  auto overlaps(const MemoryRegion& other) const noexcept -> bool
  {
    return this->end_address > other.base_address
        && this->base_address < other.end_address;
  }
};
